+import type { ConfigurableTrait, Trait, TraitRecord } from '../trait/types';
+import type { World } from './types';
+
+type Command =
+    | { type: 'spawn'; entity: Entity; traits: ConfigurableTrait[] }
+    | { type: 'destroy'; entity: Entity }
+    | { type: 'add'; entity: Entity; traits: ConfigurableTrait[] }
+    | { type: 'remove'; entity: Entity; traits: (Trait | RelationPair)[] }
+    | { type: 'exclusive'; entity: Entity; pair: RelationPair };
+
+type Scope = { commands: Command[] };
+
+export type DeferredWorld = {
+    spawn(...traits: ConfigurableTrait[]): Entity;
+    destroy(entity: Entity): void;
+    add(entity: Entity, ...traits: ConfigurableTrait[]): void;
+    remove(entity: Entity, ...traits: (Trait | RelationPair)[]): void;
+    addExclusive(entity: Entity, pair: RelationPair): void;
+    flush(): void;
+};
+
+export function createDeferred(world: World): DeferredWorld {
+    const scopes: Scope[] = [{ commands: [] }];
+    const current = () => scopes[scopes.length - 1];
+
+    const deferred: DeferredWorld = {
+        spawn(...traits) {
+            const entity = allocateEntity(world[$internal].entityIndex);
+            world[$internal].entityTraits.set(entity, new Set());
+            current().commands.push({ type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity) {
+            current().commands.push({ type: 'destroy', entity });
+        },
+        add(entity, ...traits) {
+            current().commands.push({ type: 'add', entity, traits });
+        },
+        remove(entity, ...traits) {
+            current().commands.push({ type: 'remove', entity, traits });
+        },
+        addExclusive(entity, pair) {
+            current().commands.push({ type: 'exclusive', entity, pair });
+        },
+        flush() {
+            flushScope(world, current());
+        },
+    };
+
+    world[$internal].deferredScopes = scopes;
+    world[$internal].deferred = deferred;
+    return deferred;
+}
+
+export function enterDeferredScope(world: World) {
+    world[$internal].deferredScopes!.push({ commands: [] });
+}
+
+export function exitDeferredScope(world: World) {
+    const scopes = world[$internal].deferredScopes!;
+    const scope = scopes.pop()!;
+    flushScope(world, scope);
+}
+
+export function flushPendingFor(world: World, entity: Entity) {
+    const scopes = world[$internal].deferredScopes;
+    if (!scopes || !scopes.some((scope) => scope.commands.some((command) => command.entity === entity))) return;
+    // Commands cannot be applied out of order, so flush all active scopes oldest first.
+    for (const scope of scopes) flushScope(world, scope);
+}
+
+function flushScope(world: World, scope: Scope) {
+    if (!scope.commands.length) return;
+    const commands = scope.commands.splice(0);
+    const spawned = new Set(commands.filter((c): c is Extract<Command, { type: 'spawn' }> => c.type === 'spawn').map((c) => c.entity));
+    const cancelled = new Set<Entity>();
+    for (const command of commands) if (command.type === 'destroy' && spawned.has(command.entity)) cancelled.add(command.entity);
+
+    world[$internal].deferSilenceSubscriptions = true;
+    try {
+        for (const command of commands) {
+            if (cancelled.has(command.entity)) continue;
+            if (command.type === 'spawn') {
+                // Deferred entities reserve an id early; activating them only needs their traits.
+                addTrait(world, command.entity, ...command.traits);
+                continue;
+            }
+            if (!world.has(command.entity)) continue;
+            if (command.type === 'destroy') {
+                if (command.entity === world[$internal].worldEntity) {
+                    throw new Error('Koota: The world entity cannot be destroyed through deferred commands.');
+                }
+                destroyEntity(world, command.entity);
+            } else if (command.type === 'add') {
+                for (const trait of command.traits) {
+                    addTrait(world, command.entity, trait);
+                    // `add` normally ignores an existing value. Deferred writes are last-write-wins.
+                    if (Array.isArray(trait)) setTrait(world, command.entity, trait[0], trait[1], false);
+                    else if (isRelationPair(trait) && trait[$internal].params) {
+                        setTrait(world, command.entity, trait, trait[$internal].params, false);
+                    }
+                }
+            } else if (command.type === 'remove') {
+                removeTrait(world, command.entity, ...command.traits);
+            } else {
+                const { relation } = command.pair[$internal];
+                removeTrait(world, command.entity, relation('*'));
+                if (command.pair[$internal].target !== '*') addTrait(world, command.entity, command.pair);
+            }
+        }
+    } finally {
+        world[$internal].deferSilenceSubscriptions = false;
+        for (const entity of cancelled) {
+            if (world.has(entity)) {
+                releaseEntity(world[$internal].entityIndex, entity);
+                world[$internal].entityTraits.delete(entity);
+            }
+        }
+    }
+}
+
+/** Projected reads are deliberately cheap and only inspect commands targeting this entity. */
+export function deferredHas(world: World, entity: Entity, trait: Trait | RelationPair): boolean {
+    const scopes = world[$internal].deferredScopes;
+    if (!scopes) return isRelationPair(trait) ? entity.has(trait) : hasTrait(world, entity, trait);
+    let value = isRelationPair(trait) ? entity.has(trait) : hasTrait(world, entity, trait);
+    for (const scope of scopes) for (const command of scope.commands) {
+        if (command.entity !== entity) continue;
+        if (command.type === 'destroy') value = false;
+        if (command.type === 'add' && command.traits.some((t) => sameTrait(t, trait))) value = true;
+        if (command.type === 'remove' && command.traits.some((t) => sameTrait(t, trait))) value = false;
+        if (command.type === 'exclusive' && isRelationPair(trait) && command.pair[$internal].relation === trait[$internal].relation) value = command.pair[$internal].target === trait[$internal].target;
+    }
+    return value;
+}
+
+export function deferredGet(world: World, entity: Entity, trait: Trait | RelationPair): TraitRecord<any> | undefined {
+    const scopes = world[$internal].deferredScopes;
+    if (scopes) for (let s = scopes.length - 1; s >= 0; s--) for (let i = scopes[s].commands.length - 1; i >= 0; i--) {
+        const command = scopes[s].commands[i];
+        if (command.entity !== entity || command.type !== 'add') continue;
+        for (let j = command.traits.length - 1; j >= 0; j--) {
+            const item = command.traits[j];
+            if (sameTrait(item, trait)) return Array.isArray(item) ? item[1] as TraitRecord<any> : isRelationPair(item) ? item[$internal].params as TraitRecord<any> : undefined;
+        }
+    }
+    return getTrait(world, entity, trait);
+}
+
+function sameTrait(value: ConfigurableTrait | Trait | RelationPair, trait: Trait | RelationPair) {
+    if (isRelationPair(value) || isRelationPair(trait)) return isRelationPair(value) && isRelationPair(trait) && value[$internal].relation === trait[$internal].relation && value[$internal].target === trait[$internal].target;
+    return (Array.isArray(value) ? value[0] : value) === trait;
+}
