+function snapshotSubscriptions(world: World): SubscriptionSnapshot {
+    const traits = new Map<string, [Trait, Entity, Entity?]>();
+    for (const instance of world[$internal].traitInstances) {
+        if (!instance || (!instance.addSubscriptions.size && !instance.removeSubscriptions.size)) continue;
+        const relation = instance.trait[$internal].relation;
+        for (const entity of world.entities) {
+            if (!hasTrait(world, entity, instance.trait)) continue;
+            if (relation) for (const target of getRelationTargets(world, relation, entity)) traits.set(`${instance.trait.id}:${entity}:${target}`, [instance.trait, entity, target]);
+            else traits.set(`${instance.trait.id}:${entity}`, [instance.trait, entity]);
+        }
